const { spawn } = require('child_process');
const path = require('path');

const proc = spawn('node', [path.join(__dirname, '..', '..', '..', 'src', 'cli.js'), 'context', 'embedding model comparison'], {
  cwd: __dirname.substring(0, __dirname.lastIndexOf('/gsd/')),
  stdio: ['inherit', 'pipe', 'inherit']
});

let stdout = '';
proc.stdout.on('data', (d) => stdout += d);
proc.on('close', () => {
  const lines = stdout.split('\n');
  // Find last JSON line
  const jsonLines = lines.filter(l => l.startsWith('{'));
  if (jsonLines.length === 0) {
    console.error('No JSON output found');
    process.exit(1);
  }
  const data = JSON.parse(jsonLines[jsonLines.length - 1]);

  const uniqueDocs = new Set(data.results.map(r => r.source));
  const passes = uniqueDocs.size >= 3;

  console.log('=== T03 VERIFICATION ===');
  console.log('Unique documents:', uniqueDocs.size, passes ? '✅' : '❌ (need ≥3)');
  console.log('Total results:', data.results.length);
  const counts = {};
  data.results.forEach(r => { counts[r.source] = (counts[r.source] || 0) + 1; });
  const violations = Object.entries(counts).filter(([k, n]) => n > 2);
  console.log('Max chunks per doc violations (>2):', violations.length === 0 ? 'none ✅' : JSON.stringify(violations));

  // Check no duplicate sources within same document having >2
  console.log('\nAll groups ≤2 chunks:', Object.values(counts).every(n => n <= 2) ? '✅' : '❌');
  process.exit(passes ? 0 : 1);
});

