      start = i;
      break;
    }
  }
}
if (start === -1) { console.error('No JSON found'); process.exit(1); }

// Find matching closing brace
let depth = 0;
let end = -1;
for (let i = start; i < out.length; i++) {
  if (out[i] === '{') depth++;
  else if (out[i] === '}') { depth--; if (depth === 0) { end = i + 1; break; } }
