// The JSON output is the last non-empty line (JSON.stringify with 2 indent produces pretty-print)
// Actually cli.js uses `console.log(JSON.stringify(..., null, 2))` so it's multi-line
// But we can parse from the first { to the matching }
// Simple approach: use a stack-based parser that handles strings

let start = -1;
for (let i = 0; i < out.length; i++) {
  if (out[i] === '{' && start === -1) start = i;
}
if (start === -1) { console.error('No JSON found'); process.exit(1); }

// Parse with string awareness (skip braces inside strings)
let depth = 0;
let inString = false;
let escape = false;
let end = -1;
for (let i = start; i < out.length; i++) {
  const ch = out[i];
  if (escape) { escape = false; continue; }
  if (ch === '\\') { escape = true; continue; }
  if (ch === '"') { inString = !inString; continue; }
  if (inString) continue;
  if (ch === '{') depth++;
  else if (ch === '}') { depth--; if (depth === 0) { end = i + 1; break; } }
}

const json = out.substring(start, end);
const d = JSON.parse(json);

const u = new Set(d.results.map(x => x.source));
